#include <cstdio>
#include <cstdlib>
#include <cstring>

#define MAX_N 27

static int solutions = 0;
static int size;
static int mask;

static void backtrack(int row, int left, int down, int right);

static void backtrack(int row, int left, int down, int right) {
    if (down == mask) {
        #pragma omp atomic
        solutions++;
        return;
    }
    int bitmap = mask & ~(left | down | right);
    while (bitmap) {
        int bit = bitmap & -bitmap;
        bitmap ^= bit;
        backtrack(row + 1, (left | bit) << 1, down | bit, (right | bit) >> 1);
    }
}

static void nqueen() {
    solutions = 0;
    mask = (1 << size) - 1;

    backtrack(0, 0, 0, 0);
}

int main(int argc, char *argv[]) {
    if (argc != 2) {
        printf("Usage: %s <board size (1-%d)>\n", argv[0], MAX_N);
        return 1;
    }
    size = atoi(argv[1]);
    if (size < 1 || size > MAX_N) {
        printf("Board size must be between 1 and %d\n", MAX_N);
        return 1;
    }

    #pragma omp target data map(tofrom: solutions, size, mask)
    {
        #pragma omp target
        nqueen();
    }

    printf("Number of solutions for %d-Queens problem: %d\n", size, solutions);
    return 0;
}
